use std::collections::HashMap;

struct Scoreboard {
    scores: HashMap<String, i32>,
}

impl Scoreboard {
    fn new() -> Self {
        Scoreboard { 
            scores: HashMap::new()
        }
    }

    fn update_score(&mut self, team_name: &str, points: i32) -> Result<(), String> {
        if !self.scores.contains_key(team_name) {
            return Err(format!("Team {} not found in scoreboard.", team_name));
        }

        let current = self.scores.get(team_name).copied().unwrap_or(0);
        self.scores.insert(team_name.to_string(), current + points);
        Ok(()) 
    }

    fn get_score(&self, team_name: &str) -> Option<i32> {
        self.scores.get(team_name).copied()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_initialization_and_update() {
        let mut board = Scoreboard::new();
        board.scores.insert("Lions".to_string(), 10);
        board.scores.insert("Bears".to_string(), 5);

        let result = board.update_score(&"Lions".to_string(), 3);
        assert!(result.is_ok());

        let score = board.get_score(&"Lions".to_string());
        assert_eq!(score, Some(13));
    }

    #[test]
    fn test_update_on_unknown_team() {
        let mut board = Scoreboard::new();
        board.scores.insert("Lions".to_string(), 10);

        let result = board.update_score(&"Tigers".to_string(), 2);
        assert!(result.is_err());
    }
}

use std::collections::HashMap;

struct TemplateEngine {
    data: HashMap<String, String>,
}

impl TemplateEngine {
    fn new(initial_data: Vec<(&str, &str)>) -> Self {
        let mut data = HashMap::new();
        for (key, value) in initial_data {
            data.insert(key.to_string(), value.to_string());
        }
        TemplateEngine { data }
    }

    fn get_value(&self, key: &str) -> Option<&str> {
        self.data.get(key).map(|s| s.as_str())
    }

    fn render_simple(&self, template: &str) -> String {
        let mut output = template.to_string();
        if let Some(user_name) = self.get_value("username") {
            output = output.replace("{user_placeholder}", user_name);
        }
        output
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn setup() -> TemplateEngine {
        TemplateEngine::new(vec![("username", "RustGuy"), ("item_count", "3")])
    }

    #[test]
    fn test_engine_initialization_and_retrieval() {
        let engine = setup();
        assert!(engine.get_value("username").is_some());
        assert_eq!(engine.get_value("item_count").unwrap(), "3");
        assert!(engine.get_value("nonexistent").is_none());
    }

    #[test]
    fn test_rendering_with_known_data() {
        let engine = setup();
        let template = "Welcome, {user_placeholder}! You have {item_count} items.";
        let expected = "Welcome, RustGuy! You have 3 items.";
        assert_eq!(engine.render_simple(template), expected);
    }

    #[test]
    fn test_rendering_when_data_is_missing() {
        let engine = TemplateEngine::new(vec![("item_count", "1")]);
        let template = "Welcome, {user_placeholder}! You have {item_count} items.";
        let expected = "Welcome, {user_placeholder}! You have 1 items.";
        assert_eq!(engine.render_simple(template), expected);
    }
}

use std::collections::HashMap;
use std::fs::File;
use std::io::{self, BufReader, Read};

struct LogProcessor {
    error_codes: Vec<String>,
}

impl LogProcessor {
    fn new(errors: Vec<&str>) -> Self {
        LogProcessor {
            error_codes: errors.iter().map(|&s| s.to_string()).collect(),
        }
    }

    fn process_files(&self, file_paths: &[&str]) -> io::Result<HashMap<String, u32>> {
        let mut counts: HashMap<String, u32> = HashMap::new();

        for path in file_paths {
            println!("Processing file: {}", path);
            let file = File::open(path)?;
            let mut reader = BufReader::new(file);
            let mut content = String::new();
            reader.read_to_string(&mut content)?;

            for line in content.lines() {
                if self.error_codes.iter().any(|code| line.contains(code)) {
                    *counts.entry(format!("Found Error Line in {}", path)).or_insert(0) += 1;
                }
            }
        }
        Ok(counts)
    }
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct EventProcessor {
    processed_count: Arc<Mutex<usize>>,
    state: Arc<Mutex<String>>,
}

impl EventProcessor {
    fn new() -> Self {
        EventProcessor {
            processed_count: Arc::new(Mutex::new(0)),
            state: Arc::new(Mutex::new(String::from("Idle"))),
        }
    }

    fn process_chunk(&self, chunk_id: &str, data: &[u8]) -> Result<(), String> {
        let mut state = self.state.lock().unwrap();
        if *state != "Connected" {
            return Err(format!("Cannot process; system is not in 'Connected' state."));
        }

        println!("Processing chunk: {}", chunk_id);
        std::thread::sleep(std::time::Duration::from_millis(10));

        *self.processed_count.lock().unwrap() += 1;
        let mut state = self.state.lock().unwrap();
        if *self.processed_count.lock().unwrap() >= 2 {
            *state = String::from("Finished Batch");
        }
        Ok(())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn setup() -> EventProcessor {
        let processor = EventProcessor::new();
        *processor.state.lock().unwrap() = String::from("Connected");
        processor
    }

    #[test]
    fn test_initial_state_rejection() {
        let processor = setup();
        let result = processor.process_chunk("bad_id", b"data");
        assert!(result.is_err());
        assert!(result.unwrap_err().contains("Connected"));
    }

    #[test]
    fn test_successful_batch_processing() {
        let processor = setup();
        processor.process_chunk(&String::from("a"), b"data1").unwrap();
        assert_eq!(*processor.processed_count.lock().unwrap(), 1);

        processor.process_chunk(&String::from("b"), b"data2").unwrap();
        assert_eq!(*processor.processed_count.lock().unwrap(), 2);
        assert!(processor.state.lock().unwrap().contains("Finished Batch"));
    }

    #[test]
    fn test_state_persistence_after_failure() {
        let processor = setup();
        processor.process_chunk(&String::from("a"), b"data1").unwrap();
        let initial_count = *processor.processed_count.lock().unwrap();

        *processor.state.lock().unwrap() = String::from("Error State");

        let result = processor.process_chunk(&String::from("c"), b"data3");
        assert!(result.is_err());

        assert_eq!(*processor.processed_count.lock().unwrap(), initial_count);
    }
}

use std::collections::HashMap;
use rand::{Rng, SeedableRng};
use rand::rngs::StdRng;

struct KeyValueStore {
    data: HashMap<String, Vec<f64>>,
}

impl KeyValueStore {
    fn new() -> Self {
        KeyValueStore { data: HashMap::new() }
    }

    fn insert(&mut self, key: &str, values: &[f64]) {
        let entry = self.data.entry(key.to_string()).or_insert_with(Vec::new);
        entry.extend_from_slice(values);
    }

    fn get_sum(&self, key: &str) -> Option<f64> {
        self.data.get(key).map(|v| v.iter().sum())
    }
}

#[cfg(test)]
mod tests {
    use super::KeyValueStore;

    fn setup() -> KeyValueStore {
        let mut store = KeyValueStore::new();
        store.insert("group_A", &[1.0, 2.0]);
        store.insert("group_B", &[5.0]);
        store.insert("group_A", &[3.0]);
        store.insert("group_C", &[10.0, -5.0]);
        store
    }

    #[test]
    fn test_aggregation() {
        let store = setup();
        assert!(store.get_sum(&"group_A").is_some());
        assert_eq!(store.get_sum(&"group_A").unwrap(), 6.0);
        assert_eq!(store.get_sum(&"group_B").unwrap(), 5.0);
        assert_eq!(store.get_sum(&"group_C").unwrap(), 5.0);
    }

    #[test]
    fn test_nonexistent_key() {
        let store = setup();
        assert!(store.get_sum(&"missing_group").is_none());
    }
}
